1	export interface QuoteInput {
2	  items: { type: string }[];
3	}
4	
5	const PROCESSING_FEE = 5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	};
12	
13	export function quote(input: QuoteInput): number {
14	  const basePremiumTotal = input.items.reduce(
15	    (sum, item) => sum + BASE_PREMIUMS[item.type],
16	    0,
17	  );
18	  return basePremiumTotal + PROCESSING_FEE;
19	}
